INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a3c10900-0000-4000-8000-000000000000','a3c00000-0000-4000-8000-000000000000','確認テスト ─ 中期経営計画の策定と運用','quiz',NULL,NULL,NULL,3,2),
  ('a3c20900-0000-4000-8000-000000000000','a3c00000-0000-4000-8000-000000000000','確認テスト ─ 事業ポートフォリオマネジメント','quiz',NULL,NULL,NULL,3,4),
  ('a3c30900-0000-4000-8000-000000000000','a3c00000-0000-4000-8000-000000000000','確認テスト ─ 新規事業の立ち上げ','quiz',NULL,NULL,NULL,3,6),
  ('a3c40900-0000-4000-8000-000000000000','a3c00000-0000-4000-8000-000000000000','確認テスト ─ 業績マネジメントシステム','quiz',NULL,NULL,NULL,3,8)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a3c10900-0000-4000-8000-000000000000','本文が示す中期経営計画の本質は、次のどれか。','三年後の数字を正確に当てるための、精緻な予測である','全社が向かう先への意思を、前提とともに示し、回し続けられる形にしたものである','一つの事業が市場で勝つための、戦い方の道筋である','社内をひとつにまとめるための、立派な一冊の完成品である','B',0),
('a3c10900-0000-4000-8000-000000000000','本文で、中計の価値はどこにあるとされているか。','三年先を正確に当てること','完璧な精度で一冊にまとめ切ること','ズレたとき、全社で立て直せること','発表会で社内を鼓舞できること','C',1),
('a3c10900-0000-4000-8000-000000000000','中計に必ず入れる五要素のうち、一つの事業計画と決定的に違い、経営にしかできない判断が真ん中に入るとされるのはどれか。','資源配分の方針(どの事業に、人とお金を、どう張るか)','経営の現在地(全社の数字・各事業の立ち位置)','年度への落とし込み(三年を各年の目標に分ける)','めざす姿と全社目標(三年後どこへ行くか)','A',2),
('a3c20900-0000-4000-8000-000000000000','本文が示す事業ポートフォリオマネジメントの本質は、次のどれか。','手に入れた事業を、すべて平等に愛でて持ち続けることである','事業の数を増やし、会社の柱を多くしていくことである','複数の事業を全体として捉え、限られた資源を、最も実る配分へと意思を持って動かし続けることである','各事業の損得を、それぞれ個別に最大化することである','C',0),
('a3c20900-0000-4000-8000-000000000000','本文で、事業を見る二つの軸として挙げられているのはどれか。','規模と歴史','成長(伸びるか)と収益(稼いでいるか)','人員数と投資額','思い入れと将来性','B',1),
('a3c20900-0000-4000-8000-000000000000','「見極める役割」の事業について、たたむ基準はどう決めるべきだと本文は述べているか。','感情が高ぶった、まさにその場で判断する','周囲の空気を読み、失敗と呼ばれない時機を待つ','いつまでに、何が、どうなっていなければ撤退するか、期限と数字をセットで先に決める','稼ぎ頭が黒字を出しているうちは決めない','C',2),
('a3c30900-0000-4000-8000-000000000000','本文が示す新規事業の立ち上げの本質は、次のどれか。','当たるか外れるかの一発の賭けに、全財産を投じることである','引き返す線を引いたうえで、仮説を段階的に検証していく営みである','退路を断ち、片道切符の覚悟で走り切ることである','始め方だけを綿密に設計することである','B',0),
('a3c30900-0000-4000-8000-000000000000','本文によれば、撤退基準はいつ決めるべきか。','走り出して思い入れが生まれてから','撤退線に近づき、判断が迫ってから','まだ何も注ぎ込んでいない、始める前','複数の目で見られる、会議の場で','C',1),
('a3c30900-0000-4000-8000-000000000000','「撤退線で、線を引き直す」失敗に対する修正として、本文が挙げているのはどれか。','撤退線は、達したら機械的に発動する','本人の裁量で、もう少しだけ様子を見る','手応えがあれば関門を飛ばして一気に広げる','確かめやすい仮説から先に検証する','A',2),
('a3c40900-0000-4000-8000-000000000000','本文が示す業績マネジメントシステムの本質は、次のどれか。','経営の最終目標から現場の日々の行動までを、一本の数字の鎖でつなぎ、回し続ける仕組みである','全社の目標を各部門に頭割りで割り振る仕組みである','結果の数字である売上と利益を、毎月正確に集計する仕組みである','数字で現場を締めつけ、確実に動かす仕組みである','A',0),
('a3c40900-0000-4000-8000-000000000000','本文における「結果の数字(KGI)」と「先行の数字(KPI)」の関係の説明として正しいのはどれか。','結果の数字は今から動かせ、先行の数字はもう動かせない','結果の数字は過去でもう動かせず、先行の数字は未来で今から動かせる','どちらも過去の数字であり、現場が動かせるものではない','先行の数字は経営が、結果の数字は現場が動かす','B',1),
('a3c40900-0000-4000-8000-000000000000','「目標を分解して降ろす」ステップで、本文が戒める誤りはどれか。','最終目標を一つか二つに絞ること','手前の数字へ因果(筋道)でつなぐこと','最終目標を、各部門に均等に割る足し算の割り算にすること','現場が動かせる数字まで翻訳しきること','C',2);
